sql:
SELECT rank
FROM neighborhood_businesses
WHERE neighborhood_id = 1;

SELECT business_type_id, COUNT(business_id) AS business_count
FROM neighborhood_businesses
GROUP BY business_type_id;

SELECT business_type_id, growth_rate
FROM neighborhood_trends
WHERE neighborhood_id = 0 AND year = 2023;

SELECT COUNT(*) 
FROM business_frequency 
WHERE year = 2023;

